import React from 'react';
import { Link } from 'react-router-dom';

const HeroBanner = () => {
    return (
        <div className="relative overflow-hidden bg-gradient-to-r from-blue-900 via-blue-800 to-blue-700 text-white min-h-[500px] flex items-center">
            {/* Background Image - School Building */}
            <div 
                className="absolute inset-0 bg-cover bg-center"
                style={{
                    backgroundImage: "url('/images/school-building.jpg')",
                    backgroundSize: 'cover',
                    backgroundPosition: 'center'
                }}
            ></div>
            
            {/* Dark Overlay for readability */}
            <div className="absolute inset-0 bg-gradient-to-r from-blue-900/80 via-blue-800/70 to-blue-700/60"></div>
            
            {/* Content */}
            <div className="relative z-10 max-w-7xl mx-auto px-4 py-16 w-full">
                <div className="flex flex-col md:flex-row items-center gap-8">
                    {/* Left Side - Text */}
                    <div className="flex-1 text-center md:text-left">
                        {/* Science Fair Banner Image */}
                        <img 
                            src="/images/science-fair-banner.jpg" 
                            alt="Science Fair 2026-27" 
                            className="max-w-xs mx-auto md:mx-0 rounded-lg shadow-2xl mb-6 border-4 border-yellow-400/50"
                            onError={(e) => {
                                // If image fails, show text instead
                                e.target.style.display = 'none';
                            }}
                        />
                        
                        <h1 className="text-4xl md:text-6xl font-bold mb-4">
                            ⚡ Spark 4.0
                        </h1>
                        <p className="text-xl md:text-2xl text-blue-200 mb-2">
                            Science Fair 2026-27
                        </p>
                        <p className="text-lg text-blue-300 mb-6">
                            Podar International School, Latur · Khadgoan Ring Road
                        </p>
                        
                        <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                            <Link to="/register" className="bg-yellow-400 text-blue-900 px-8 py-3 rounded-full font-bold hover:bg-yellow-300 transition shadow-lg transform hover:scale-105">
                                📝 Register Now
                            </Link>
                            <Link to="/login" className="bg-white/20 backdrop-blur-sm text-white px-8 py-3 rounded-full font-bold hover:bg-white/30 transition border border-white/30">
                                🔐 Login
                            </Link>
                        </div>
                    </div>
                    
                    {/* Right Side - Stats */}
                    <div className="flex-1 grid grid-cols-2 gap-4 max-w-md">
                        <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg text-center border border-white/20">
                            <p className="text-3xl font-bold text-yellow-400">9</p>
                            <p className="text-sm text-blue-200">Divisions</p>
                        </div>
                        <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg text-center border border-white/20">
                            <p className="text-3xl font-bold text-yellow-400">8</p>
                            <p className="text-sm text-blue-200">Projects per Class</p>
                        </div>
                        <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg text-center border border-white/20">
                            <p className="text-3xl font-bold text-yellow-400">4-10</p>
                            <p className="text-sm text-blue-200">Grades</p>
                        </div>
                        <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg text-center border border-white/20">
                            <p className="text-3xl font-bold text-yellow-400">🏆</p>
                            <p className="text-sm text-blue-200">Top 3 Winners</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default HeroBanner;
